const {
  NORDIC_ISLAND_ENTRYPOINT,
  IMPORT_TYPES,
} = require('../../constants/islands');
const {
  RELATIVE_PATH_REGEX,
  NODE_SUBPATH_IMPORT_REGEX,
} = require('../../constants/regexs');
const { importsCache } = require('../../cache/imports-cache');
const { pathHasAlias } = require('../aliases');

/**
 * @typedef {Object} PotencialComponent
 * @property {string?} importName - Name used to export in the origin path
 * @property {string} path
 * @property {boolean} namedExport
 *
 * @typedef {Object} ImportDynamicCaller
 * @property {string} [type]
 * @property {string} file
 * @property {string} [module]
 *
 * @typedef {Object} Component
 * @property {string} importName - Name used to export in the origin path
 * @property {string} path
 * @property {boolean} namedExport
 * @property {boolean} isIsland
 * @property {{} | import('../file-system/islands-manifest').IslandsManifest?} [islands]
 * @property {ImportDynamicCaller} [importDynamicCaller]
 *
 * @typedef {{ [localName: string]: Component }} ComponentManifest
 */

/**
 * @param {string | null} path
 */
const getComponentTypeByPath = (path) => {
  if (path === NORDIC_ISLAND_ENTRYPOINT) {
    return IMPORT_TYPES.NORDIC_ISLAND;
  }

  if (RELATIVE_PATH_REGEX.test(path)) {
    return IMPORT_TYPES.RELATIVE;
  }

  if (pathHasAlias(path)) {
    return IMPORT_TYPES.NORDIC_ALIAS;
  }

  if (NODE_SUBPATH_IMPORT_REGEX.test(path)) {
    return IMPORT_TYPES.NODE_SUBPATH;
  }

  return null;
};

/**
 * @param {ComponentManifest} destination
 * @param {{ localName: string, component: PotencialComponent }} component
 */
const addComponentToDestinationIfValid = (
  destination,
  { localName, component },
) => {
  if (!component.importName) {
    return;
  }

  component.isIsland = false;
  destination[localName] = component;

  const cachedImportIslands = importsCache.getImport(component);

  if (!cachedImportIslands) {
    return;
  }

  destination[localName].islands = cachedImportIslands;
};

module.exports = {
  getComponentTypeByPath,
  addComponentToDestinationIfValid,
};
